sql:
SELECT location, COUNT(garden_id) AS total_gardens
FROM gardens
GROUP BY location;

SELECT name, email
FROM garden_members
WHERE STRFTIME('%Y', joined_at) > '2020';

SELECT name, role
FROM garden_members
ORDER BY joined_at DESC;

external_knowledge:
- "vibrant gardens" refers to gardens with a high number of members and coordinators;
- "abundance of their members" refers to the total number of unique members;
- "leadership of their coordinators" refers to the number of members with the role of coordinator;
- "rank" is determined by the combination of member count and coordinator count, with member count taking precedence.

- 'Above Average Yield' indicates a yield greater than the average yield across all gardens;
- 'Below Average Yield' indicates a yield less than the average yield across all gardens;
- 'Average Yield' indicates a yield equal to the average yield across all gardens;
- 'Has Pest Report' indicates that the garden has reported at least one pest;
- 'No Pest Report' indicates that the garden has not reported any pests.

- 'fully funded' refers to gardens with a funding status of 'Funded';
- 'guiding light' refers to a member with a role of 'Coordinator';
- 'received' and 'monetary' indicate that the donations are both accepted and in the form of money.

sql:
SELECT MAX(event_count) AS max_events
FROM (
  SELECT COUNT(event_id) AS event_count
  FROM events
  GROUP BY garden_id
);

SELECT name, funding_status
FROM gardens
ORDER BY name ASC;

SELECT COUNT(DISTINCT d.garden_id) AS gardens_with_received_donations
FROM donations d
WHERE d.donation_status = 'Received';

external_knowledge:
- 'workshop' refers to a specific type of event;
- 'Volunteer' is a specific role of a member in the garden;
- The total count includes all events, pest reports, resources, and members associated with each garden.

- 'Garden of Eden' is a metaphorical reference to a well-maintained and resource-rich environment;
- 'Flourishing' indicates that the garden has more than 50 resources and 10 members;
- 'Secured their funding' means the garden's funding status is 'funded';
- 'Face the wrath of pests' refers to the number of pest reports in the garden.

sql:
SELECT garden_id
FROM gardens
WHERE garden_type = 'Vegetables' AND area = (SELECT MAX(area) FROM gardens WHERE garden_type = 'Vegetables');

SELECT role, COUNT(member_id) AS member_count
FROM garden_members
GROUP BY role;

SELECT DISTINCT T1.name 
FROM garden_members AS T1 
INNER JOIN workshops AS T2 ON T1.garden_id = T2.garden_id;

SELECT AVG(total_yield) AS average_bounty
FROM (
  SELECT garden_id, SUM(yield) AS total_yield
  FROM crops
  GROUP BY garden_id
) AS garden_yields;

external_knowledge:
- 'Vibrant gardens' refers to gardens with a high number of members and resources;
- 'Community size' refers to the number of distinct members in the garden;
- 'Resource abundance' refers to the total quantity of resources available in the garden;
- 'Resources per member' is calculated by dividing the total quantity of resources by the number of members in the garden.
